from __future__ import annotations


def check_access(role, permission, matrix, log, include_reason=False):
    role_known = role in matrix
    allowed = permission in matrix.get(role, set())
    row = {'role': role, 'permission': permission, 'allowed': allowed}
    if include_reason:
        if allowed:
            row['reason'] = 'allowed'
        elif not role_known:
            row['reason'] = 'unknown_role'
        else:
            row['reason'] = 'missing_permission'
    log.append(row)
    return allowed
